const express = require('express');
const app = express();

// Middleware to log requests
app.use((req, res, next) => {
  const apiKey = req.query.api_key;
  console.log(`${new Date().toISOString()} - Request received for path ${req.url} with API key: ${apiKey}`);
  req.headers['x-api-key'] = apiKey; // Add the API key to request headers
  next();
});

// Route handler for forwarding requests to backend services
app.get('*', (req, res) => {
  const targetUrl = `http://${req.headers['x-api-key']}:8081${req.url}`; // Replace 8081 with the port number of your backend service
  req.pipe(require('request')).end().pipe(res);
});

// Start the server on port 3000
app.listen(3000, () => {
  console.log(`API gateway is listening on port ${3000}`);
});